1591     if (!R.IsSigned) {
1592       for (Value *V : NewVariables) {
1593         ConstraintTy VarPos(SmallVector<int64_t, 8>(Value2Index.size() + 1, 0),
1594                             false, false, false);
1595         VarPos.Coefficients[Value2Index[V]] = -1;
