1541 
1542   // Remove entries again.
1543   while (OldSize < DFSInStack.size()) {
1544     StackEntry E = DFSInStack.back();
1545     removeEntryFromStack(E, Info, ReproducerModule, ReproducerCondStack,
1546                          DFSInStack);
1547   }
1548   return Changed;
